package com.example.app;

import com.fasterxml.jackson.databind.ObjectMapper;
import org.apache.kafka.clients.producer.KafkaProducer;
import org.apache.kafka.clients.producer.ProducerRecord;
import org.apache.kafka.common.serialization.StringSerializer;

import java.util.Map;
import java.util.Properties;

public class EventPublisher {
    private final KafkaProducer<String, String> producer;
    public EventPublisher() {
        Properties p = new Properties();
        p.put("bootstrap.servers", System.getenv("BOOTSTRAP_SERVER"));
        p.put("key.serializer", StringSerializer.class.getName());
        p.put("value.serializer", StringSerializer.class.getName());
        this.producer = new KafkaProducer<>(p);
    }
    public void publish(String topic, Map<String,Object> event) throws Exception {
        producer.send(new ProducerRecord<>(topic, new ObjectMapper().writeValueAsString(event)));
    }
}
